import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Encode user input to prevent XSS
        String safeUserInput = encodeForHTML(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("User input: " + safeUserInput); // Output the properly encoded user input
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHTML(String input) {
        // You can use OWASP Java Encoder library for HTML encoding
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
